## Code Example

```javascript
class Node { constructor(val){ this.val=val; this.prio=Math.random(); this.l=null; this.r=null; this.sz=1; this.gcd=val; } }
function sz(n){return n? n.sz:0}
function gcd(a,b){ while(b){ let t=a%b; a=b; b=t;} return Math.abs(a); }
function upd(n){ if(!n) return; n.sz = 1 + sz(n.l) + sz(n.r); const gl = n.l? n.l.gcd:0; const gr = n.r? n.r.gcd:0; n.gcd = gcd(gcd(gl, n.val), gr); }
function split(n, k){ if(!n) return [null, null]; if(sz(n.l) >= k){ const [a,b] = split(n.l, k); n.l=b; upd(n); return [a, n]; } else { const [a,b] = split(n.r, k - sz(n.l) -1); n.r=a; upd(n); return [n, b]; } }
function merge(a,b){ if(!a||!b) return a||b; if(a.prio < b.prio){ a.r = merge(a.r, b); upd(a); return a; } else { b.l = merge(a, b.l); upd(b); return b; } }
// Insert, erase, rangeGCD usage explained in prose
